import{_ as s,c as l,o as t,a5 as a,j as e}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.1.2: Stability Fixes","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.1.2.md","filePath":"en/changelog/v1.1.2.md","lastUpdated":1772014034000}'),r={name:"en/changelog/v1.1.2.md"};function o(n,i,d,h,c,u){return t(),l("div",null,[...i[0]||(i[0]=[a('<h1 id="v1-1-2-stability-fixes" tabindex="-1">v1.1.2: Stability Fixes <a class="header-anchor" href="#v1-1-2-stability-fixes" aria-label="Permalink to “v1.1.2: Stability Fixes”">​</a></h1><p><strong>Release Date</strong>: 2026-01-05</p><p>One-line summary: Fixed permission matching issues, added session search, desktop experience improvements.</p><hr><h2 id="new-features" tabindex="-1">New Features <a class="header-anchor" href="#new-features" aria-label="Permalink to “New Features”">​</a></h2><h3 id="session-search" tabindex="-1">Session Search <a class="header-anchor" href="#session-search" aria-label="Permalink to “Session Search”">​</a></h3><p>Now you can quickly search through historical sessions! Supports debounced input and server-side filtering.</p><p><strong>How to use</strong>: Use the search function in the session list interface.</p><p><strong>Benefits</strong>: When you have many sessions, no need to scroll through them one by one - just search by keyword.</p><hr><h2 id="bug-fixes" tabindex="-1">Bug Fixes <a class="header-anchor" href="#bug-fixes" aria-label="Permalink to “Bug Fixes”">​</a></h2><h3 id="core-fixes" tabindex="-1">Core Fixes <a class="header-anchor" href="#core-fixes" aria-label="Permalink to “Core Fixes”">​</a></h3><ul><li>Permission rule matching now uses <code>permission</code> field instead of <code>pattern</code> field</li><li>Permission evaluation changed from wildcard to rule matching</li><li>Gracefully handle <code>.claude</code> file scan failures</li><li>Handle fallback when big-pickle is unavailable</li><li>Prevent main model thinking variants from applying to small models</li><li>Default timeout increased to 30 seconds</li></ul><h3 id="tui-fixes" tabindex="-1">TUI Fixes <a class="header-anchor" href="#tui-fixes" aria-label="Permalink to “TUI Fixes”">​</a></h3><ul><li>Allow exit when viewing sub-sessions</li><li>Input box symmetric padding</li><li>Prevent session list rows from wrapping to two lines</li></ul><h3 id="desktop-fixes" tabindex="-1">Desktop Fixes <a class="header-anchor" href="#desktop-fixes" aria-label="Permalink to “Desktop Fixes”">​</a></h3><ul><li>Slash popup auto-scroll</li><li>Responsive menu fixes</li><li>Mobile screen size issues</li><li>Custom slash commands not showing initially</li></ul><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to “Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Your Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>Experiencing permission matching issues</td><td>✅ Must upgrade</td></tr><tr><td>Using desktop version</td><td>✅ Recommended</td></tr><tr><td>Everything works fine</td><td>Optional</td></tr></tbody></table><hr><h2 id="upgrade-command" tabindex="-1">Upgrade Command <a class="header-anchor" href="#upgrade-command" aria-label="Permalink to “Upgrade Command”">​</a></h2>',22),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),a('<hr><h2 id="technical-details" tabindex="-1">Technical Details <a class="header-anchor" href="#technical-details" aria-label="Permalink to “Technical Details”">​</a></h2><details><summary>Click to view full changes</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Fixed permission rule matching using permission field</li><li>Fixed permission evaluation using rule matching</li><li>Gracefully handle skill scan failures</li><li>Improved Rust formatter detection, added cargo fmt support</li><li>Increased default timeout to 30 seconds</li></ul><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h3><ul><li>Allow exit when viewing sub-sessions</li><li>Fixed input box symmetric padding</li><li>Prevent session list wrapping</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Slash popup auto-scroll</li><li>Responsive menu fixes</li><li>Added main icon</li><li>SVG preview support</li><li>AppStream MetaInfo file</li><li>Mobile screen size fixes</li><li>Custom slash command display fix</li></ul><h3 id="contributors-11" tabindex="-1">Contributors (11) <a class="header-anchor" href="#contributors-11" aria-label="Permalink to “Contributors (11)”">​</a></h3><p>@melihmucuk, @rgodha24, @albingroen, @Raviguntala, @carterworks, @NN708, @shuv1337, @dbpolito, @shkumbinhasani, @OpeOginni, @rmk40</p></details><hr><p><a href="./">← Back to Changelog</a></p>',5)])])}const f=s(r,[["render",o]]);export{m as __pageData,f as default};
